# config/claude_client.py
import anthropic
from functools import lru_cache

@lru_cache(maxsize=1)
def get_client() -> anthropic.AsyncAnthropic:
    """Return the singleton AsyncAnthropic client."""
    return anthropic.AsyncAnthropic(
        max_retries=3,          # SDK-native retry (exponential back-off)
        timeout=60.0,           # seconds; override per-call for long streaming
    )

def extract_text(response) -> str:
    """Return concatenated text from all text blocks in a response."""
    return "".join(
        block.text
        for block in response.content
        if block.type == "text"
    )

def extract_tool_calls(response) -> list:
    """Return all tool_use blocks in a response."""
    return [block for block in response.content if block.type == "tool_use"]
